import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as l,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"WebDAV-доступ к сайту (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Safety/webdav-site-access.md","filePath":"ru-RU/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),n={name:"ru-RU/Safety/webdav-site-access.md"};function o(s,e,h,p,b,c){return l(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="webdav-доступ-к-саиту-beta" tabindex="-1">WebDAV-доступ к сайту (Beta) <a class="header-anchor" href="#webdav-доступ-к-саиту-beta" aria-label="Permalink to &quot;WebDAV-доступ к сайту (Beta)&quot;">​</a></h1><p>Настройка WebDAV в Security Settings открывает ваш сайт ImgBed как WebDAV endpoint.</p><p>После включения можно использовать Windows, macOS, мобильные файловые менеджеры или любой WebDAV-совместимый клиент, чтобы просматривать, загружать, удалять и управлять файлами ImgBed как удаленной папкой.</p><p>Это вход WebDAV-доступа именно к сайту. Он отличается от WebDAV storage channel в настройках загрузки. Канал загрузки хранит файлы в стороннем WebDAV-сервисе. Эта настройка позволяет вашему сайту ImgBed предоставлять WebDAV-доступ клиентам.</p><h2 id="где-это-настраивается" tabindex="-1">Где это настраивается <a class="header-anchor" href="#где-это-настраивается" aria-label="Permalink to &quot;Где это настраивается&quot;">​</a></h2><p>Откройте админ-панель и перейдите в:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Доступные настройки:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="что-делает-эта-функция" tabindex="-1">Что делает эта функция <a class="header-anchor" href="#что-делает-эта-функция" aria-label="Permalink to &quot;Что делает эта функция&quot;">​</a></h2><p>После включения WebDAV ImgBed предоставляет фиксированный URL доступа:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>Используйте этот URL для подключения к файловой директории ImgBed.</p><p>Полезные сценарии:</p><ul><li>просматривать файлы ImgBed напрямую из файлового менеджера компьютера;</li><li>перетаскивать изображения в WebDAV-папку для загрузки;</li><li>упорядочивать папки ImgBed из локального файлового менеджера;</li><li>использовать WebDAV-совместимое ПО для синхронизации или управления изображениями;</li><li>получать доступ к содержимому ImgBed без открытия админ-панели.</li></ul><h2 id="настроики" tabindex="-1">Настройки <a class="header-anchor" href="#настроики" aria-label="Permalink to &quot;Настройки&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>Включает WebDAV endpoint.</p><p>Когда выключено, клиенты не могут подключиться через WebDAV.</p><h3 id="username-и-password" tabindex="-1">Username и Password <a class="header-anchor" href="#username-и-password" aria-label="Permalink to &quot;Username и Password&quot;">​</a></h3><p>Эти учетные данные используются WebDAV-клиентами при подключении.</p><p>Используйте отдельные WebDAV username и password. Не используйте повторно admin password или upload password.</p><p>Если username или password пустые, WebDAV-клиенты не смогут подключаться корректно.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode определяет, какой URL изображения WebDAV-клиенты предпочитают при чтении изображений.</p><p>Распространенные варианты:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Описание</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed выбирает по контексту. Рекомендуется для обычного использования.</td></tr><tr><td>Original</td><td>Предпочитать оригинальные изображения.</td></tr><tr><td>Thumbnail</td><td>Предпочитать миниатюры. Полезно для быстрого preview.</td></tr></tbody></table><p>Если не уверены, оставьте <code>Smart loading</code>.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>Default channel используется для WebDAV-загрузок.</p><p>Когда вы копируете файлы в WebDAV-директорию из Windows или другого клиента, ImgBed загружает их через выбранный default upload channel.</p><p>Если default channel не выбран, просмотр может работать, но загрузка может падать.</p><h2 id="доступ-к-webdav-в-windows-11" tabindex="-1">Доступ к WebDAV в Windows 11 <a class="header-anchor" href="#доступ-к-webdav-в-windows-11" aria-label="Permalink to &quot;Доступ к WebDAV в Windows 11&quot;">​</a></h2><p>Windows 11 может добавить WebDAV как network location.</p><ol><li>Откройте <code>This PC</code>.</li><li>Выберите <code>Add a network location</code>.</li><li>Введите <code>https://your-domain.com/dav</code>.</li><li>Когда появится запрос, введите WebDAV username и password.</li><li>Завершите мастер. После этого WebDAV-директорию можно открыть в File Explorer.</li></ol><p><img src="'+a+'" alt="Добавление WebDAV в Windows 11" loading="lazy"></p><p>После добавления WebDAV-директория появится в Windows File Explorer. Можно открывать, копировать и управлять файлами как в обычной папке.</p><p><img src="'+t+'" alt="WebDAV в Windows" loading="lazy"></p><h2 id="поддерживаемые-операции" tabindex="-1">Поддерживаемые операции <a class="header-anchor" href="#поддерживаемые-операции" aria-label="Permalink to &quot;Поддерживаемые операции&quot;">​</a></h2><p>После успешного WebDAV-подключения обычно можно:</p><ul><li>просматривать файлы и папки;</li><li>загружать файлы;</li><li>создавать папки;</li><li>переименовывать файлы или папки;</li><li>перемещать файлы;</li><li>удалять файлы.</li></ul><p>WebDAV лучше подходит для повседневного доступа и небольшого управления файлами. Для крупных перемещений, массовых удалений или сложной организации лучше использовать админ-панель.</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>Успешные WebDAV-подключения также появляются на вкладке WebDAV в Login Device Management.</p><p>Там можно просматривать WebDAV-клиенты и при необходимости принудительно выводить старые устройства офлайн.</p><p>Если изменить WebDAV username или password, старым клиентам нужно будет войти снова.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-постоянно-спрашивает-username-и-password" tabindex="-1">Windows постоянно спрашивает username и password <a class="header-anchor" href="#windows-постоянно-спрашивает-username-и-password" aria-label="Permalink to &quot;Windows постоянно спрашивает username и password&quot;">​</a></h3><p>Проверьте:</p><ul><li>URL должен быть <code>https://your-domain.com/dav</code>.</li><li>Username и password совпадают с настройками WebDAV.</li><li>WebDAV включен.</li><li>Сайт доступен через HTTPS.</li></ul><h3 id="просмотр-работает-но-загрузка-нет" tabindex="-1">Просмотр работает, но загрузка нет <a class="header-anchor" href="#просмотр-работает-но-загрузка-нет" aria-label="Permalink to &quot;Просмотр работает, но загрузка нет&quot;">​</a></h3><p>Проверьте <code>Default channel</code>.</p><p>Для WebDAV-загрузок нужен default upload channel. Если его нет, он выключен или неправильно настроен, загрузка может не работать.</p><h3 id="скорость-доступа-нестабильна" tabindex="-1">Скорость доступа нестабильна <a class="header-anchor" href="#скорость-доступа-нестабильна" aria-label="Permalink to &quot;Скорость доступа нестабильна&quot;">​</a></h3><p>Производительность WebDAV зависит от клиента, сети, количества файлов и default upload channel.</p><p>Если в директории много файлов, разложите их по папкам, а не держите слишком много файлов в одной директории.</p><h2 id="рекомендации-по-безопасности" tabindex="-1">Рекомендации по безопасности <a class="header-anchor" href="#рекомендации-по-безопасности" aria-label="Permalink to &quot;Рекомендации по безопасности&quot;">​</a></h2><ul><li>Используйте HTTPS для WebDAV-доступа.</li><li>Установите надежный пароль.</li><li>Не передавайте WebDAV password людям, которым не доверяете.</li><li>Выключайте WebDAV, когда не пользуетесь им.</li><li>Периодически очищайте неиспользуемые WebDAV devices в Login Device Management.</li></ul><h2 id="размер-фаилов-для-webdav-загрузки" tabindex="-1">Размер файлов для WebDAV-загрузки <a class="header-anchor" href="#размер-фаилов-для-webdav-загрузки" aria-label="Permalink to &quot;Размер файлов для WebDAV-загрузки&quot;">​</a></h2><p>WebDAV-клиенты не используют browser upload page&#39;s large-file chunking flow. Для файлов больше рекомендованных ниже лимитов используйте веб-страницу загрузки.</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">Рекомендуемый лимит одного файла для WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const D=i(n,[["render",o]]);export{m as __pageData,D as default};
